function strng3 = fGet3NmbStringV01(nmb)% gives a string of number in three digit Tony's labview format,% e.g., 3 -> 003%% strng3 = fGet3NmbStringV01(nmb)% % nmb: number% strng3: output string%% *********************************% Get 3 nuber string, ver.1% Kei Nakamura% Created on Thursday, May 6th 2010.% Modified on %% mainaNmb = abs(nmb);if aNmb<10    strng3 = ['00',num2str(aNmb)];   % scan number string for savingelseif aNmb<100    strng3 = ['0',num2str(aNmb)];else    strng3 = num2str(aNmb);endif nmb<0    strng3 = ['-',strng3];end
